"""Агентский tool-calling loop.

Архитектура: chat completion с tools=[...]. Модель сама решает, какой
шаг следующий. Цикл крутится до `final_answer` или max_iterations.
"""

from __future__ import annotations

import json
import logging
from dataclasses import dataclass, field
from typing import Any, Protocol

from .prompts import SYSTEM_PROMPT
from .tools import TOOL_SCHEMAS, FinalAnswer, ToolDispatcher

log = logging.getLogger(__name__)


class _ChatClient(Protocol):
    """Минимальный интерфейс, нужный агенту от OpenAI SDK.

    Используется для подмены клиента в тестах.
    """

    @property
    def chat(self) -> Any: ...  # pragma: no cover


@dataclass
class AgentRun:
    answer: str
    supporting_data: dict[str, Any]
    iterations: int
    trace: list[dict[str, Any]] = field(default_factory=list)


class Agent:
    """Tool-calling агент. Передаёшь client + dispatcher + model."""

    def __init__(
        self,
        client: _ChatClient,
        dispatcher: ToolDispatcher,
        model: str,
        max_iterations: int = 10,
        temperature: float = 0.0,
    ):
        self._client = client
        self._dispatcher = dispatcher
        self._model = model
        self._max_iterations = max_iterations
        self._temperature = temperature

    def run(self, question: str) -> AgentRun:
        messages: list[dict[str, Any]] = [
            {"role": "system", "content": SYSTEM_PROMPT},
            {"role": "user", "content": question},
        ]
        trace: list[dict[str, Any]] = []

        for step in range(1, self._max_iterations + 1):
            log.info("Agent step %d", step)
            response = self._client.chat.completions.create(
                model=self._model,
                messages=messages,
                tools=TOOL_SCHEMAS,
                tool_choice="auto",
                temperature=self._temperature,
            )
            choice = response.choices[0]
            msg = choice.message
            tool_calls = getattr(msg, "tool_calls", None) or []

            # Сохраняем assistant-сообщение целиком (с tool_calls).
            assistant_record: dict[str, Any] = {
                "role": "assistant",
                "content": msg.content or "",
            }
            if tool_calls:
                assistant_record["tool_calls"] = [
                    {
                        "id": tc.id,
                        "type": "function",
                        "function": {
                            "name": tc.function.name,
                            "arguments": tc.function.arguments,
                        },
                    }
                    for tc in tool_calls
                ]
            messages.append(assistant_record)

            if not tool_calls:
                # LLM решила ответить напрямую без вызова final_answer.
                text = (msg.content or "").strip() or "Пустой ответ от модели."
                trace.append({"step": step, "tool": None, "raw_text": text})
                return AgentRun(
                    answer=text,
                    supporting_data={"note": "model returned no tool_call"},
                    iterations=step,
                    trace=trace,
                )

            final: FinalAnswer | None = None
            for tc in tool_calls:
                name = tc.function.name
                raw_args = tc.function.arguments or "{}"
                try:
                    args = json.loads(raw_args) if isinstance(raw_args, str) else raw_args
                except json.JSONDecodeError as e:
                    args = {}
                    result: Any = {"error": f"Невалидный JSON в arguments: {e}"}
                else:
                    result = self._dispatcher.dispatch(name, args)

                trace.append(
                    {
                        "step": step,
                        "tool": name,
                        "args": args,
                        "result_preview": _preview(result),
                    }
                )

                if isinstance(result, FinalAnswer):
                    final = result
                    tool_content = json.dumps(
                        {"status": "delivered", "text_preview": result.text[:200]},
                        ensure_ascii=False,
                    )
                else:
                    tool_content = _to_json_safe(result)

                messages.append(
                    {
                        "role": "tool",
                        "tool_call_id": tc.id,
                        "name": name,
                        "content": tool_content,
                    }
                )

            if final is not None:
                return AgentRun(
                    answer=final.text,
                    supporting_data=final.supporting_data,
                    iterations=step,
                    trace=trace,
                )

        # Лимит итераций исчерпан.
        log.warning("Agent hit max_iterations=%d", self._max_iterations)
        return AgentRun(
            answer=(
                "Не удалось получить финальный ответ за "
                f"{self._max_iterations} шагов. Попробуйте переформулировать "
                "вопрос или сузить период."
            ),
            supporting_data={"reason": "max_iterations_exceeded"},
            iterations=self._max_iterations,
            trace=trace,
        )


def _preview(value: Any, limit: int = 400) -> str:
    try:
        s = json.dumps(value, ensure_ascii=False, default=str)
    except (TypeError, ValueError):
        s = str(value)
    return s if len(s) <= limit else s[:limit] + "…"


def _to_json_safe(value: Any) -> str:
    """Сериализуем tool-результат для отправки в LLM."""
    try:
        return json.dumps(value, ensure_ascii=False, default=str)
    except (TypeError, ValueError):
        return json.dumps({"repr": repr(value)}, ensure_ascii=False)

"""OpenAI-совместимые tool-описания + dispatcher.

Каждый tool возвращает dict, который сериализуется в JSON и пихается
обратно в conversation как роль `tool`.
"""

from __future__ import annotations

import json
import logging
from dataclasses import dataclass
from typing import Any, Callable

from .db import OracleClient, SQLSafetyError, assert_safe_select
from .schema import UnknownTableError, inspect_table, list_tables
from .validator import validate

log = logging.getLogger(__name__)


TOOL_SCHEMAS: list[dict[str, Any]] = [
    {
        "type": "function",
        "function": {
            "name": "inspect_schema",
            "description": (
                "Вернуть структуру таблицы из metadata.py: список полей, "
                "описания на русском, правила агрегации, SQL-примеры. "
                "Вызывай ОБЯЗАТЕЛЬНО первым шагом, прежде чем составлять SQL."
            ),
            "parameters": {
                "type": "object",
                "properties": {
                    "table": {
                        "type": "string",
                        "description": "Имя таблицы. Сейчас доступна 'client_product'.",
                    },
                },
                "required": ["table"],
            },
        },
    },
    {
        "type": "function",
        "function": {
            "name": "execute_sql",
            "description": (
                "Выполнить read-only SELECT/WITH запрос в Oracle и вернуть "
                "table-like результат: columns, rows, row_count. Разрешены "
                "только SELECT/WITH (без DDL/DML и без ';' в середине). "
                "Используй ТОЛЬКО поля и таблицы, известные через "
                "inspect_schema."
            ),
            "parameters": {
                "type": "object",
                "properties": {
                    "sql": {
                        "type": "string",
                        "description": (
                            "Oracle SQL. Используй DATE 'YYYY-MM-DD' для дат, "
                            "FETCH FIRST N ROWS ONLY для лимитов, не клади ';' "
                            "в конец."
                        ),
                    },
                },
                "required": ["sql"],
            },
        },
    },
    {
        "type": "function",
        "function": {
            "name": "validate_result",
            "description": (
                "Sanity-проверка результата execute_sql. Возвращает список "
                "warnings (пусто → результат правдоподобен). Вызывай ПЕРЕД "
                "final_answer, чтобы убедиться, что числа не нулевые/NULL/"
                "пустые."
            ),
            "parameters": {
                "type": "object",
                "properties": {
                    "result": {
                        "type": "object",
                        "description": (
                            "Объект {columns, rows, row_count, truncated}, "
                            "полученный от execute_sql. Передавай как есть."
                        ),
                    },
                    "expectations": {
                        "type": "object",
                        "description": (
                            "Опционально: {min_rows, max_rows, "
                            "non_null_columns, non_negative_columns}."
                        ),
                    },
                },
                "required": ["result"],
            },
        },
    },
    {
        "type": "function",
        "function": {
            "name": "final_answer",
            "description": (
                "Сформировать итоговый ответ пользователю на русском языке. "
                "Обязательно: укажи реальные цифры из БД, единицы (рубли, шт.), "
                "период / фильтры. Если данных не нашлось — честно скажи. "
                "Вызов этого tool'а завершает диалог."
            ),
            "parameters": {
                "type": "object",
                "properties": {
                    "text": {
                        "type": "string",
                        "description": (
                            "Финальный NL-ответ на русском. 1-5 предложений, "
                            "с конкретными цифрами и единицами."
                        ),
                    },
                    "supporting_data": {
                        "type": "object",
                        "description": (
                            "Опциональный JSON с ключевыми числами для "
                            "трассировки (sql, key_values и т.п.)."
                        ),
                    },
                },
                "required": ["text"],
            },
        },
    },
]


@dataclass
class FinalAnswer:
    """Сигнал агента 'я закончил'."""

    text: str
    supporting_data: dict[str, Any]


class ToolDispatcher:
    """Соединяет имена tool'ов с реальными хендлерами."""

    def __init__(self, oracle: OracleClient):
        self._oracle = oracle
        self._handlers: dict[str, Callable[[dict[str, Any]], Any]] = {
            "inspect_schema": self._inspect_schema,
            "execute_sql": self._execute_sql,
            "validate_result": self._validate_result,
            "final_answer": self._final_answer,
        }

    def dispatch(self, name: str, args: dict[str, Any]) -> Any:
        """Возвращает результат tool'а. Может вернуть FinalAnswer-сигнал."""
        handler = self._handlers.get(name)
        if handler is None:
            return {"error": f"Неизвестный tool: {name!r}"}
        try:
            return handler(args)
        except Exception as exc:  # noqa: BLE001 — LLM должен видеть ошибку.
            log.warning("Tool %s failed: %s", name, exc, exc_info=True)
            return {"error": f"{type(exc).__name__}: {exc}"}

    # ----- handlers -----

    def _inspect_schema(self, args: dict[str, Any]) -> dict[str, Any]:
        table = (args.get("table") or "client_product").strip()
        try:
            return inspect_table(table)
        except UnknownTableError as e:
            return {
                "error": str(e),
                "available_tables": list_tables(),
            }

    def _execute_sql(self, args: dict[str, Any]) -> dict[str, Any]:
        sql = (args.get("sql") or "").strip()
        if not sql:
            return {"error": "Пустой sql."}
        # Defence-in-depth: safety на уровне dispatcher не зависит от
        # реализации Oracle-клиента (важно для тестов и при подмене БД).
        try:
            assert_safe_select(sql)
        except SQLSafetyError as e:
            return {"error": f"SQLSafetyError: {e}"}
        try:
            qr = self._oracle.execute_select(sql)
        except SQLSafetyError as e:
            return {"error": f"SQLSafetyError: {e}"}
        return qr.to_dict()

    def _validate_result(self, args: dict[str, Any]) -> dict[str, Any]:
        result = args.get("result") or {}
        expectations = args.get("expectations") or {}
        if isinstance(result, str):
            # Иногда LLM упаковывает result в строку — попробуем распарсить.
            try:
                result = json.loads(result)
            except json.JSONDecodeError:
                return {"error": "result должен быть объектом, не строкой."}
        return validate(result, expectations).to_dict()

    def _final_answer(self, args: dict[str, Any]) -> FinalAnswer:
        text = (args.get("text") or "").strip()
        supporting = args.get("supporting_data") or {}
        if isinstance(supporting, str):
            try:
                supporting = json.loads(supporting)
            except json.JSONDecodeError:
                supporting = {"raw": supporting}
        if not text:
            text = "Не удалось сформулировать ответ."
        return FinalAnswer(text=text, supporting_data=supporting)

"""Тонкая обёртка над oracledb: connect, execute_select, format_result."""

from __future__ import annotations

import datetime as dt
import logging
import re
from dataclasses import dataclass, field
from decimal import Decimal
from typing import Any

import oracledb

from .config import Config

log = logging.getLogger(__name__)

# Только read-only запросы. Любая DDL/DML — отклоняется.
_ALLOWED_PREFIX = re.compile(r"^\s*(SELECT|WITH)\b", re.IGNORECASE)
_FORBIDDEN = re.compile(
    r"\b(INSERT|UPDATE|DELETE|MERGE|DROP|ALTER|CREATE|TRUNCATE|GRANT|REVOKE|EXEC|CALL|BEGIN)\b",
    re.IGNORECASE,
)


class SQLSafetyError(ValueError):
    """SQL не прошёл проверку безопасности."""


def assert_safe_select(sql: str) -> None:
    """Разрешаем только SELECT / WITH. Без trailing ';'.

    Поднимаем SQLSafetyError на любые признаки мутации.
    """
    stripped = sql.strip().rstrip(";").strip()
    if not stripped:
        raise SQLSafetyError("Пустой SQL.")
    if not _ALLOWED_PREFIX.match(stripped):
        raise SQLSafetyError(
            "Разрешены только SELECT / WITH запросы (получено: "
            f"{stripped[:40]!r}…)."
        )
    # Защита от multi-statement через ';' в середине.
    if ";" in stripped:
        raise SQLSafetyError("Multi-statement SQL не поддерживается.")
    if _FORBIDDEN.search(stripped):
        raise SQLSafetyError("SQL содержит запрещённые ключевые слова (DDL/DML).")


@dataclass
class QueryResult:
    columns: list[str]
    rows: list[list[Any]]
    row_count: int
    truncated: bool = False
    warnings: list[str] = field(default_factory=list)

    def to_dict(self) -> dict[str, Any]:
        return {
            "columns": self.columns,
            "rows": self.rows,
            "row_count": self.row_count,
            "truncated": self.truncated,
            "warnings": self.warnings,
        }


def _to_jsonable(value: Any) -> Any:
    """Конвертим Oracle-специфичные типы в JSON-совместимые."""
    if value is None:
        return None
    if isinstance(value, Decimal):
        # NUMBER → int если целое, иначе float.
        if value == value.to_integral_value():
            return int(value)
        return float(value)
    if isinstance(value, (dt.datetime, dt.date)):
        return value.isoformat()
    if isinstance(value, bytes):
        try:
            return value.decode("utf-8")
        except UnicodeDecodeError:
            return value.hex()
    return value


class OracleClient:
    """Менеджер соединений (один short-lived connect на запрос)."""

    def __init__(self, cfg: Config, row_limit: int = 1000):
        self._cfg = cfg
        self._row_limit = row_limit

    def execute_select(self, sql: str) -> QueryResult:
        assert_safe_select(sql)
        log.debug("Executing SQL: %s", sql)
        with oracledb.connect(
            user=self._cfg.oracle_username,
            password=self._cfg.oracle_password,
            dsn=self._cfg.oracle_dsn,
        ) as conn:
            with conn.cursor() as cur:
                cur.execute(sql)
                cols: list[str] = [str(d[0]) for d in (cur.description or [])]
                fetched = cur.fetchmany(self._row_limit + 1)
                truncated = len(fetched) > self._row_limit
                if truncated:
                    fetched = fetched[: self._row_limit]
                rows = [[_to_jsonable(v) for v in row] for row in fetched]
        return QueryResult(
            columns=cols,
            rows=rows,
            row_count=len(rows),
            truncated=truncated,
        )

"""Sanity-валидация результата SQL-запроса.

Лёгкая, ad-hoc: проверяем размер, нулевые значения в ключевых ячейках,
разумные диапазоны числовых полей. Цель — поймать «пустой результат»,
«всё NaN», «отрицательная сумма», но не заменить human review.
"""

from __future__ import annotations

from dataclasses import dataclass, field
from typing import Any


@dataclass
class ValidationReport:
    ok: bool
    warnings: list[str] = field(default_factory=list)
    summary: str = ""

    def to_dict(self) -> dict[str, Any]:
        return {"ok": self.ok, "warnings": self.warnings, "summary": self.summary}


def _is_number(v: Any) -> bool:
    return isinstance(v, (int, float)) and not isinstance(v, bool)


def validate(
    result: dict[str, Any],
    expectations: dict[str, Any] | None = None,
) -> ValidationReport:
    """Sanity-проверка result (dict из QueryResult.to_dict()).

    expectations поддерживает:
      - min_rows: int (default 0)
      - max_rows: int | None
      - non_null_columns: list[str] — хотя бы одна непустая ячейка
      - non_negative_columns: list[str] — все значения >= 0
    """
    expectations = expectations or {}
    warnings: list[str] = []

    columns = list(result.get("columns") or [])
    rows = list(result.get("rows") or [])
    row_count = int(result.get("row_count") or 0)

    min_rows = int(expectations.get("min_rows", 0))
    max_rows = expectations.get("max_rows")

    if row_count < min_rows:
        warnings.append(
            f"Получено {row_count} строк, ожидалось не меньше {min_rows}."
        )
    if max_rows is not None and row_count > int(max_rows):
        warnings.append(
            f"Получено {row_count} строк, ожидалось не больше {max_rows}."
        )
    if row_count == 0:
        warnings.append("Результат пуст — нет данных для интерпретации.")

    if result.get("truncated"):
        warnings.append(
            "Результат был усечён лимитом строк — возможна потеря данных."
        )

    col_idx = {c: i for i, c in enumerate(columns)}

    for col in expectations.get("non_null_columns") or []:
        if col not in col_idx:
            warnings.append(f"Колонка {col!r} отсутствует в результате.")
            continue
        i = col_idx[col]
        if rows and all((r[i] is None) for r in rows):
            warnings.append(f"Колонка {col!r} полностью NULL.")

    for col in expectations.get("non_negative_columns") or []:
        if col not in col_idx:
            warnings.append(f"Колонка {col!r} отсутствует в результате.")
            continue
        i = col_idx[col]
        for r in rows:
            if r[i] is not None and _is_number(r[i]) and r[i] < 0:
                warnings.append(
                    f"Колонка {col!r} содержит отрицательные значения "
                    f"(пример: {r[i]})."
                )
                break

    summary = (
        f"rows={row_count}, columns={columns}, "
        f"warnings={len(warnings)}"
    )
    return ValidationReport(ok=not warnings, warnings=warnings, summary=summary)

